 p_id=>wwv_flow_imp.id(51951791590921260)
,p_lov_name=>'FILE_USER'
,p_lov_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    DISPLAY_VALUE,',
'    RETURN_VALUE',
'FROM (',
unistr('    -- \0627\0644\062D\0627\0644\0629 1: \0639\0645\0644\0627\0621'),
'    SELECT ',
'        C.CUST_NAME AS DISPLAY_VALUE,',
'        TO_CHAR(C.CUSTID) AS RETURN_VALUE',
'    FROM CUST C',
'    WHERE EXISTS (',
'        SELECT 1 FROM FILE_TRANSFER F ',
'         WHERE F.FROM_TYPE = 1 ',
'           AND F.CUSTOMER = TO_CHAR(C.CUSTID)',
'    )',
'',
'    UNION ALL',
'',
unistr('    -- \0627\0644\062D\0627\0644\0629 0: \062C\0647\0627\062A \062D\0643\0648\0645\064A\0629'),
'    SELECT ',
'        DISTINCT F.GOVERNMENT_AGENCY AS DISPLAY_VALUE,',
'        F.GOVERNMENT_AGENCY AS RETURN_VALUE',
'    FROM FILE_TRANSFER F',
'    WHERE F.FROM_TYPE = 0',
'      AND F.GOVERNMENT_AGENCY IS NOT NULL',
'',
'    UNION ALL',
'',
unistr('    -- \0627\0644\062D\0627\0644\0629 2: \0645\0648\0638\0641\064A\0646'),
'    SELECT ',
'        U.REAL_NAME AS DISPLAY_VALUE,',
'        U.USER_NAME AS RETURN_VALUE',
'    FROM ACC_USERS U',
'    WHERE EXISTS (',
'        SELECT 1 FROM FILE_TRANSFER F',
'         WHERE F.FROM_TYPE = 2',
'           AND F.EMPLOYEE = U.USER_NAME',
'    )',
')',
'ORDER BY DISPLAY_VALUE;',
''))
,p_source_type=>'SQL'
,p_location=>'LOCAL'
,p_return_column_name=>'RETURN_VALUE'
,p_display_column_name=>'DISPLAY_VALUE'
,p_group_sort_direction=>'ASC'
,p_default_sort_column_name=>'DISPLAY_VALUE'
,p_default_sort_direction=>'ASC'
,p_version_scn=>205002737
);
