,p_lov_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
' SELECT M.INV_KEY, INVID,INVDATE,M.ITEMNAME,finaltotal,PAYED,NVL(finaltotal,0)-NVL(PAYED,0) REMAIN,NOTES FROM (',
' select  INV_KEY, INVID,INVDATE,CUST_NAME,main_inv.cust_id,finaltotal,',
' (select  sum (NVL(MP.SDAD,0)) from main_inv_payed MP WHERE INV_KEY=main_inv.INV_KEY) PAYED,',
' (SELECT ITEMNAME FROM   DETAIL_INV JOIN ITEMS USING(ITEMID) WHERE INV_KEY=main_inv.INV_KEY AND ROWNUM<2 )  ITEMNAME,',
' (SELECT NOTES FROM   DETAIL_INV WHERE INV_KEY=main_inv.INV_KEY AND ROWNUM<2 )  NOTES',
'from main_inv ,cust',
'where 	main_inv.INVTYPE=0  AND RETURN_FLAG=0',
' and( main_inv.cust_id=:P19_ID)  ',
'AND main_inv.cust_type=cust.CUST_TYPE and main_inv.cust_id=cust.custid',
'and  cust.CUST_TYPE=0',
') M --LEFT JOIN (SELECT INV_KEY,ITEMNAME,NOTES FROM DETAIL_INV JOIN ITEMS USING(ITEMID) WHERE INV_KEY=M.INV_KEY AND  ROWNUM<2) D ON (M.INV_KEY=D.INV_KEY)',
'WHERE (NVL(finaltotal,0)-NVL(PAYED,0)>0 or inv_key=:p19_inv_key)',
'order by invdate,invid',
'',
''))
,p_source_type=>'SQL'
