prompt --application/shared_components/user_interface/lovs/original_invoices_to_return
begin
wwv_flow_imp_shared.create_list_of_values(
 p_id=>wwv_flow_imp.id(205941255918049913)
,p_lov_name=>'ORIGINAL_INVOICES_TO_RETURN'
,p_lov_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT distinct ',
'    ISSUER_BRANCHNAME,',
'    INV_KEY,',
'    CUST_ID,',
'    CUST_NAME,',
'    INVDATE,',
'    INVID,',
'    TOTAL,',
'    ADD_VAL,',
'    SUB_VAL,',
'    NET,',
'    STATUS,',
'    CASE',
'        WHEN NVL(SUM_PAYED, 0) >= NVL(NET, 0) THEN 0',
'        WHEN NVL(SUM_PAYED, 0) < NVL(NET, 0) AND NVL(SUM_PAYED, 0) > 0 THEN 1',
'        WHEN NVL(SUM_PAYED, 0) = 0 THEN 2',
'    END PAYED_STATUS,',
'    SUM_PAYED,',
'    NET - NVL(SUM_PAYED, 0) REMAIN,NVL(DETAIL_NOTES,NOTES) NOTES',
'FROM',
'    (',
'        SELECT',
'            ISSUER_BRANCHNAME,',
'            M.INV_KEY,',
'            CUST_ID,',
'            CUST_NAME,',
'            INVDATE,',
'            M.INVID,',
'            -- price,',
'            SUM(DECODE(RETURN_FLAG, 0, NVL(PRICE, 0) * NVL(DETAIL_INV.QTY, 0), NVL(PRICE, 0) * NVL(DETAIL_INV.QTY, 0) * -1)) OVER (PARTITION BY DETAIL_INV.INV_KEY) TOTAL,',
'            SUM(NVL(DETAIL_INV.ADD_VAL, 0)) OVER (PARTITION BY DETAIL_INV.INV_KEY)  ADD_VAL,',
'            SUM(NVL(DETAIL_INV.SUB_VAL, 0)) OVER (PARTITION BY DETAIL_INV.INV_KEY) SUB_VAL,',
'            SUM(',
'                DECODE(',
'                    RETURN_FLAG,',
'                    0,',
'                    (NVL(PRICE, 0) * NVL(DETAIL_INV.QTY, 0)) + NVL(DETAIL_INV.ADD_VAL, 0) - NVL(DETAIL_INV.SUB_VAL, 0),',
'                    (NVL(PRICE, 0) * NVL(DETAIL_INV.QTY, 0)) + NVL(DETAIL_INV.ADD_VAL, 0) - NVL(DETAIL_INV.SUB_VAL, 0) * -1',
'                )',
'            ) OVER (PARTITION BY DETAIL_INV.INV_KEY) NET,',
'            HEAD_NOTES NOTES,',
'            DECODE(',
'                NVL(CHECKED, 0),',
'                0,',
unistr('                ''\062C\062F\064A\062F'','),
'                1,',
'                DECODE(',
'                    STATUS,',
'                    ''0'',',
unistr('                    ''\062A\0645\062A \0627\0644\0645\0631\0627\062C\0639\0647 \0648\0644\0645 \062A\0631\0633\0644'','),
'                    ''1'',',
unistr('                    ''\062A\0645 \0627\0644\0627\0631\0633\0627\0644'','),
'                    ''2'',',
unistr('                    ''\062E\0637\0623 \0641\0649 \0627\0644\0627\0631\0633\0627\0644'''),
'                )',
'            ) STATUS,',
'            ',
'            (',
'                SELECT SUM(NVL(SDAD, 0))',
'                FROM MAIN_INV_PAYED',
'                WHERE INV_KEY = M.INV_KEY',
'            ) SUM_PAYED,FIRST_VALUE(NOTES IGNORE NULLS) OVER (PARTITION BY DETAIL_INV.INV_KEY) DETAIL_NOTES',
'        FROM',
'            MAIN_INV m',
'        LEFT JOIN',
'            DETAIL_INV ON (M.INV_KEY = DETAIL_INV.INV_KEY)',
'        JOIN',
'            CUST ON (M.CUST_ID = CUST.CUSTID AND M.CUST_TYPE = CUST.CUST_TYPE)',
'        JOIN',
'         ISSUER ON (BRANCHID = ISSUER_BRANCHID)join acc_users on ((M.BRANCHID=acc_users.BRANCHID and upper(USER_NAME)=:app_user) or (upper(USER_NAME)=:app_user and acc_users.BRANCHID =99) ) ',
'',
'        WHERE RETURN_FLAG = 0 and not exists(select '''' from main_inv where original_inv_key=inv_key and return_flag=1)',
'           ',
'        /*group by ISSUER_BRANCHNAME,',
'        M.inv_key,CUST_ID , CUST_NAME,',
'        INVDATE ,M.INVID,M.head_notes,NVL(CHECKED ,0),STATUS,NVL(finaltotal,0))*/',
'        ORDER BY',
'            INVDATE DESC,',
'            M.INV_KEY DESC',
'    )',
'ORDER BY',
'    INVDATE DESC,',
'    INV_KEY DESC;'))
,p_source_type=>'SQL'
