,p_plug_display_column=>1
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    TASK_ID AS EVENT_ID,',
'    TASK_NAME||''_''||cust_name AS EVENT_NAME,',
'    START_PLAN_DATE AS EVENT_START_DATE,',
'    END_PLAN_DATE AS EVENT_END_DATE,',
'    TASK_DESC AS EVENT_DETAILS,',
'    CASE ',
'        WHEN END_ACTUAL_DATE IS NOT NULL THEN ''Completed''',
'        WHEN START_ACTUAL_DATE IS NOT NULL THEN ''In Progress''',
'        ELSE ''Not Started''',
'    END AS EVENT_STATUS,CASE ',
'    WHEN END_ACTUAL_DATE IS NOT NULL THEN ''completed-task''',
'    WHEN START_ACTUAL_DATE IS NOT NULL THEN ''in-progress-task''',
'    ELSE ''not-started-task''',
'END AS CSS_CLASS ',
'  FROM CUST_TASKS CT, CUST C',
' WHERE CT.CUST_ID = c.CUSTID',
''))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_CSS_CALENDAR'
