'    SUM(NVL(receipt_amount, 0) - NVL(expense_amount, 0)) AS cumulative_balance',
'FROM (',
unistr('    -- \0631\0635\064A\062F \0623\0648\0644 \0627\0644\0645\062F\0629 (\062C\0645\064A\0639 \0627\0644\062D\0631\0643\0627\062A \0642\0628\0644 \0623\064A \062A\0627\0631\064A\062E \0645\062D\062F\062F\060C \064A\0645\0643\0646 \0627\0644\0627\0639\062A\0645\0627\062F \0639\0644\0649 \0623\0642\062F\0645 \062A\0627\0631\064A\062E)'),
'    SELECT ',
'        employee_id,',
'        employee_name,',
'        CASE WHEN SUM(NVL(receipt_amount, 0) - NVL(expense_amount, 0)) > 0 THEN ',
'            SUM(NVL(receipt_amount, 0) - NVL(expense_amount, 0)) END AS receipt_amount,',
'        CASE WHEN SUM(NVL(receipt_amount, 0) - NVL(expense_amount, 0)) < 0 THEN ',
'            ABS(SUM(NVL(receipt_amount, 0) - NVL(expense_amount, 0))) END AS expense_amount',
'    FROM (',
unistr('        -- \0627\0644\062D\0631\0643\0627\062A \0627\0644\0645\062F\064A\0646\0629 (\0627\0633\062A\0644\0627\0645)'),
'        SELECT ',
'            TO_CHAR(d.ID) AS employee_id,',
'            u.REAL_NAME AS employee_name,',
'            d.AMOUNT AS receipt_amount,',
'            NULL AS expense_amount',
'        FROM ',
'            CASH_TRANS_HEAD h',
'        JOIN ',
'            CASH_TRANS_DETAIL d ON h.TRANS_ID = d.TRANS_ID',
'        JOIN ',
'            ACC_USERS u ON d.ID = u.USER_NAME',
'        WHERE ',
'            d.AMOUNT > 0',
'',
'        UNION ALL',
'',
unistr('        -- \0627\0644\062D\0631\0643\0627\062A \0627\0644\062F\0627\0626\0646\0629 (\0635\0631\0641)'),
'        SELECT ',
'            h.USER_NAME AS employee_id,',
'            u.REAL_NAME AS employee_name,',
'            NULL AS receipt_amount,',
'            d.AMOUNT AS expense_amount',
'        FROM ',
'            CUSTODY_HEAD h',
'        JOIN ',
'            ACC_USERS u ON h.USER_NAME = u.USER_NAME',
'        LEFT JOIN ',
'            CUSTODY_DETAIL d ON h.ID = d.ID',
'        WHERE ',
'            d.AMOUNT IS NOT NULL',
'    )',
'    GROUP BY employee_id, employee_name',
'',
'    UNION ALL',
'',
unistr('    -- \0627\0644\062D\0631\0643\0627\062A \0627\0644\062D\0627\0644\064A\0629 (\062C\0645\064A\0639 \0627\0644\062D\0631\0643\0627\062A \0628\062F\0648\0646 \0641\0644\062A\0631\0629 \0627\0644\062A\0627\0631\064A\062E)'),
'    SELECT ',
'        employee_id,',
'        employee_name,',
'        receipt_amount,',
'        expense_amount',
'    FROM (',
unistr('        -- \0627\0644\062D\0631\0643\0627\062A \0627\0644\0645\062F\064A\0646\0629 (\0627\0633\062A\0644\0627\0645)'),
'        SELECT ',
'            TO_CHAR(d.ID) AS employee_id,',
'            u.REAL_NAME AS employee_name,',
'            d.AMOUNT AS receipt_amount,',
'            NULL AS expense_amount',
'        FROM ',
'            CASH_TRANS_HEAD h',
'        JOIN ',
'            CASH_TRANS_DETAIL d ON h.TRANS_ID = d.TRANS_ID',
'        JOIN ',
'            ACC_USERS u ON d.ID = u.USER_NAME',
'        WHERE ',
'            d.AMOUNT > 0',
'',
'        UNION ALL',
'',
unistr('        -- \0627\0644\062D\0631\0643\0627\062A \0627\0644\062F\0627\0626\0646\0629 (\0635\0631\0641)'),
'        SELECT ',
'            h.USER_NAME AS employee_id,',
'            u.REAL_NAME AS employee_name,',
'            NULL AS receipt_amount,',
'            d.AMOUNT AS expense_amount',
'        FROM ',
'            CUSTODY_HEAD h',
'        JOIN ',
'            ACC_USERS u ON h.USER_NAME = u.USER_NAME',
'        LEFT JOIN ',
'            CUSTODY_DETAIL d ON h.ID = d.ID',
'        WHERE ',
'        d.AMOUNT IS NOT NULL',
'    )',
')',
'GROUP BY employee_id, employee_name',
'ORDER BY employee_id;'))
,p_series_name_column_name=>'EMPLOYEE_ID'
,p_items_value_column_name=>'CUMULATIVE_BALANCE'
,p_items_label_column_name=>'EMPLOYEE_NAME'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>false
