wwv_flow_imp_page.create_page(
 p_id=>5
,p_name=>'CUSTODY'
,p_alias=>'CUSTODY'
,p_step_title=>'CUSTODY'
,p_warn_on_unsaved_changes=>'N'
,p_autocomplete_on_off=>'OFF'
,p_javascript_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'',
'',
'function parseNumber(text) {',
'    return parseFloat(text.replace(/,/g, ''''));',
'}',
'',
'(function($) {',
'    function update(model) {',
'        var amountKey = model.getFieldKey("AMOUNT"),',
'            total = 0;',
'           //  $s("P5_SM_AMOUNT", 6);',
'',
'        console.log(">> starting calculation for column AMOUNT");',
'',
'        model.forEach(function(record, index, id) {',
'            var amount = parseFloat(record[amountKey]) || 0,',
'                meta = model.getRecordMetadata(id);',
'',
'            if (!isNaN(amount) && !meta.deleted && !meta.agg) {',
'                total += amount;',
'            }',
'        //     $s("P5_SM_AMOUNT", 5);',
'        });',
'',
'        console.log(">> setting summary item: P5_SM_AMOUNT");',
'',
'        // Update summary item',
'        $s("P5_SM_AMOUNT", parseFloat(total.toFixed(2)));',
'        //$s("P5_SM_AMOUNT", 1);',
'',
'',
'        console.log(">> calculation completed.");',
'    }',
'',
'    $(function() {',
'        $("#CUSTODY_DETAIL").on("interactivegridviewmodelcreate", function(event, ui) {',
'            var sid,',
'                model = ui.model;',
'',
'            if (ui.viewId === "grid") {',
'                sid = model.subscribe({',
'                    onChange: function(type, change) {',
'                        console.log(">> model changed ", type, change);',
'                        if (type === "set") {',
'                            if (["AMOUNT"].includes(change.field)) {',
'                                update(model);',
'                           //     $s("P5_SM_AMOUNT", 2);',
'                            }',
'                        } else if (type !== "move" && type !== "metaChange") {',
'                            update(model);',
'                         //   $s("P5_SM_AMOUNT", 3);',
'                        }',
'                    },',
'                    progressView: $("#P5_SM_AMOUNT") // Assuming progressView is P5_SM_AMOUNT for simplicity',
'                });',
'                ',
'                update(model);',
'                model.fetchAll(function() {});',
'            }',
'        });',
'    });',
'',
'})(apex.jQuery);',
'',
'',
''))
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'02'
);
