 p_id=>wwv_flow_imp.id(210310601439509098)
,p_plug_name=>'FILTER'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(272231373997647602)
,p_plug_display_sequence=>10
,p_include_in_reg_disp_sel_yn=>'Y'
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'expand_shortcuts', 'N',
  'output_as', 'HTML')).to_clob
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(211327836778412979)
,p_plug_name=>'EMPLOYEE_TRANSACTION'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(272260547812647624)
,p_plug_display_sequence=>20
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
unistr('-- \0643\0634\0641 \0627\0644\062D\0633\0627\0628 \0645\0639 \0641\0635\0644 \0627\0644\062D\0631\0643\0627\062A \0627\0644\0645\062F\064A\0646\0629 \0648\0627\0644\062F\0627\0626\0646\0629 \0648\062D\0633\0627\0628 \0627\0644\0631\0635\064A\062F \0627\0644\062A\0631\0627\0643\0645\064A'),
'SELECT ',
'    employee_id, ',
'    employee_name, ',
'    TRANS_CODE, ',
'    TRANS_DATE, ',
'    receipt_amount, ',
'    expense_amount, ',
'    NOTES ,emp_balance(employee_id) BALANCE,SEQ,',
unistr('    -- \062D\0633\0627\0628 \0627\0644\0631\0635\064A\062F \0627\0644\062A\0631\0627\0643\0645\064A \0628\0627\0633\062A\062E\062F\0627\0645 SUM() OVER()'),
'    SUM(NVL(receipt_amount, 0) - NVL(expense_amount, 0)) ',
'    OVER (PARTITION BY employee_id ORDER BY employee_id,TRANS_DATE,SEQ,TRANS_CODE) AS cumulative_balance',
'FROM (',
unistr('    -- \0627\0633\062A\0639\0644\0627\0645 \0627\0644\062D\0631\0643\0627\062A \0627\0644\0645\062F\064A\0646\0629 (\0627\0633\062A\0644\0627\0645 \0627\0644\0639\0647\062F\0629)'),
'    SELECT ',
'        TO_CHAR(d.ID) AS employee_id, ',
'        u.REAL_NAME AS employee_name, ',
'        h.TRANS_CODE, ',
'        h.TRANS_DATE, ',
unistr('        d.AMOUNT AS receipt_amount,   -- \0627\0644\062D\0631\0643\0627\062A \0627\0644\0645\062F\064A\0646\0629'),
unistr('        NULL AS expense_amount,       -- \0644\0627 \062A\0648\062C\062F \062D\0631\0643\0629 \062F\0627\0626\0646\0629 \0647\0646\0627'),
'        h.NOTES,0 SEQ',
'    FROM ',
'        CASH_TRANS_HEAD h',
'    JOIN ',
'        CASH_TRANS_DETAIL d ON h.TRANS_ID = d.TRANS_ID',
'    JOIN ',
'        ACC_USERS u ON  D.ID = u.USER_NAME',
'    WHERE ',
'        d.AMOUNT > 0',
'        AND (:P10_USER_NAME=0 OR TO_CHAR(D.ID)=:P10_USER_NAME)',
'    ',
'    UNION ALL',
'    ',
unistr('    -- \0627\0633\062A\0639\0644\0627\0645 \0627\0644\062D\0631\0643\0627\062A \0627\0644\062F\0627\0626\0646\0629 (\0635\0631\0641 \0627\0644\0639\0647\062F\0629)'),
'    SELECT ',
'        h.USER_NAME AS employee_id, ',
'        u.REAL_NAME AS employee_name, ',
'        h.TRANS_CODE, ',
'        h.TRANS_DATE, ',
unistr('        NULL AS receipt_amount,      -- \0644\0627 \062A\0648\062C\062F \062D\0631\0643\0629 \0645\062F\064A\0646\0629 \0647\0646\0627'),
unistr('        SUM(d.AMOUNT) AS expense_amount,  -- \0627\0644\062D\0631\0643\0627\062A \0627\0644\062F\0627\0626\0646\0629'),
'        h.NOTES,1 SEQ',
'    FROM ',
'        CUSTODY_HEAD h',
'    JOIN ',
'        ACC_USERS u ON h.USER_NAME = u.USER_NAME',
'    LEFT JOIN ',
'        CUSTODY_DETAIL d ON h.ID = d.ID',
'        WHERE  (:P10_USER_NAME=0 OR TO_CHAR(h.USER_NAME)=:P10_USER_NAME)',
'    GROUP BY ',
'        h.USER_NAME, u.REAL_NAME, h.NOTES, h.TRANS_CODE, h.TRANS_DATE',
'      ORDER BY 1,4,8,3',
') ',
'ORDER BY ',
unistr('    EMPLOYEE_ID,         -- \062A\0631\062A\064A\0628 \062D\0633\0628 \0627\0633\0645 \0627\0644\0645\0648\0638\0641'),
unistr('    TRANS_DATE,            -- \062A\0631\062A\064A\0628 \062D\0633\0628 \062A\0627\0631\064A\062E \0627\0644\062D\0631\0643\0629'),
unistr('    SEQ,TRANS_CODE           -- \062A\0631\062A\064A\0628 \062D\0633\0628 \0631\0642\0645 \0627\0644\062D\0631\0643\0629'),
''))
,p_plug_source_type=>'NATIVE_IR'
,p_ajax_items_to_submit=>'P10_USER_NAME'
,p_prn_page_header=>'EMPLOYEE_TRANSACTION'
);
