wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(154287007054749074)
,p_process_sequence=>40
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'duplicate'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'IF :P13_REPEAT-1>0 THEN ',
'DECLARE',
unistr('    v_repeat NUMBER := :P13_REPEAT-1; -- \0639\062F\062F \0627\0644\062A\0643\0631\0627\0631\0627\062A \0645\0646 \0627\0644\062D\0642\0644'),
unistr('    v_task_id NUMBER := :P13_TASK_ID; -- \0645\0639\0631\0641 \0627\0644\0633\062C\0644 \0627\0644\0645\0631\0627\062F \0646\0633\062E\0647'),
unistr('    v_task CUST_TASKS%ROWTYPE; -- \0645\062A\063A\064A\0631 \0644\062A\062E\0632\064A\0646 \0628\064A\0627\0646\0627\062A \0627\0644\0633\062C\0644'),
unistr('    v_start_plan_date DATE; -- \0627\0644\062A\0627\0631\064A\062E \0627\0644\0641\0639\0644\064A \0644\0644\0628\062F\0627\064A\0629'),
unistr('    v_end_plan_date DATE; -- \0627\0644\062A\0627\0631\064A\062E \0627\0644\0641\0639\0644\064A \0644\0644\0646\0647\0627\064A\0629'),
'BEGIN',
unistr('    -- \062C\0644\0628 \0628\064A\0627\0646\0627\062A \0627\0644\0633\062C\0644 \0627\0644\0645\062D\062F\062F'),
'    SELECT *',
'    INTO v_task',
'    FROM CUST_TASKS',
'    WHERE TASK_ID = v_task_id;',
'',
' ',
unistr('        -- \062D\0644\0642\0629 \0644\062A\0643\0631\0627\0631 \0639\0645\0644\064A\0629 \0627\0644\0625\062F\062E\0627\0644'),
'        FOR i IN 1..v_repeat LOOP',
unistr('            -- \062A\0639\062F\064A\0644 \0627\0644\062A\0648\0627\0631\064A\062E \0644\062A\0643\0648\0646 \0641\064A \0627\0644\0634\0647\0631 \0627\0644\062A\0627\0644\064A'),
'            v_start_plan_date := ADD_MONTHS(v_task.START_PLAN_DATE, I);',
'            v_end_plan_date := ADD_MONTHS(v_task.END_PLAN_DATE, I);',
'',
'            INSERT INTO CUST_TASKS (',
'                TASK_NAME,',
'                TASK_DESC,',
'                START_PLAN_DATE,',
'                END_PLAN_DATE,',
'                START_ACTUAL_DATE,',
'                END_ACTUAL_DATE,',
'                CANCEL_CHK,',
'                REMIND_BEFOR_START,',
'                REMIND_EVERY,',
'                CUST_ID,',
'                USER_NAME,',
'                NOTES',
'            ) VALUES (',
'                v_task.TASK_NAME,',
'                v_task.TASK_DESC,',
'                v_start_plan_date,',
'                v_end_plan_date,',
'                v_task.START_ACTUAL_DATE,',
'                v_task.END_ACTUAL_DATE,',
'                v_task.CANCEL_CHK,',
'                v_task.REMIND_BEFOR_START,',
'                v_task.REMIND_EVERY,',
'                v_task.CUST_ID,',
'                v_task.USER_NAME,',
'                v_task.NOTES',
'            );',
'        END LOOP;',
unistr('        -- \062A\0623\0643\064A\062F \0627\0644\0625\062F\062E\0627\0644'),
'        COMMIT;',
'',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
'        APEX_ERROR.ADD_ERROR(',
unistr('            p_message => ''\0644\0645 \064A\062A\0645 \0627\0644\0639\062B\0648\0631 \0639\0644\0649 \0627\0644\0633\062C\0644 \0627\0644\0645\062D\062F\062F.'','),
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
'    WHEN OTHERS THEN',
'        APEX_ERROR.ADD_ERROR(',
unistr('            p_message => ''\062D\062F\062B \062E\0637\0623: '' || SQLERRM,'),
'            p_display_location => APEX_ERROR.C_INLINE_IN_NOTIFICATION',
'        );',
'END;',
'    END IF;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(283085437793150680)
,p_internal_uid=>18182047465009603
);
