begin
wwv_flow_imp_page.create_page(
 p_id=>17
,p_name=>' invoice'
,p_alias=>'INVOICE1'
,p_step_title=>' invoice'
,p_warn_on_unsaved_changes=>'N'
,p_autocomplete_on_off=>'OFF'
,p_javascript_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'function parseNumber(text) {',
'    return parseFloat(text.replace(/,/g, ''''));',
'}',
'',
'(function($) {',
'    function update(model) {',
'        var qtyKey = model.getFieldKey("QTY"),',
'            priceKey = model.getFieldKey("PRICE"),',
'            addValKey = model.getFieldKey("ADD_VAL"),',
'            subValKey = model.getFieldKey("SUB_VAL"),',
'         //   totalKey = model.getFieldKey("LINE_TOTAL"),',
'            total = 0,',
'            totalbefortax = 0,',
'            tax = 0;',
'',
'        console.log(">> starting calculation for columns QTY, PRICE, ADD_VAL, SUB_VAL");',
'',
'        model.forEach(function(record, index, id) {',
'            var qty = parseFloat(record[qtyKey]) || 0,',
'                price = parseFloat(record[priceKey]) || 0,',
'                addVal = parseFloat(record[addValKey]) || 0,',
'                subVal = parseFloat(record[subValKey]) || 0,',
'                meta = model.getRecordMetadata(id);',
'',
'            if (!isNaN(qty) && !isNaN(price) && !isNaN(addVal) && !isNaN(subVal) && !meta.deleted && !meta.agg) {',
'                //var rowTotal = (qty * price) + addVal - subVal;',
'               // record[totalKey] = parseFloat(rowTotal.toFixed(2));',
'                total += (qty * price) + addVal - subVal;',
'                totalbefortax += qty * price;',
'                tax += addVal;',
'            }',
'        });',
'',
'        console.log(">> setting summary items: P17_NET, P17_INVTOTAL, P17_SUM_TAX");',
'',
'        // Update summary items',
'        $s("P17_NET", parseFloat(total.toFixed(2)));',
'        $s("P17_INVTOTAL", parseFloat(totalbefortax.toFixed(2)));',
'        $s("P17_SUM_TAX", parseFloat(tax.toFixed(2)));',
'',
'        console.log(">> calculation completed.");',
'    }',
'',
'    $(function() {',
'        $("#INV").on("interactivegridviewmodelcreate", function(event, ui) {',
'            var sid,',
'                model = ui.model;',
'',
'            if (ui.viewId === "grid") {',
'                sid = model.subscribe({',
'                    onChange: function(type, change) {',
'                        console.log(">> model changed ", type, change);',
'                        if (type === "set") {',
'                            if (["QTY", "PRICE", "ADD_VAL", "SUB_VAL"].includes(change.field)) {',
'                                update(model);',
'                            }',
'                        } else if (type !== "move" && type !== "metaChange") {',
'                            update(model);',
'                        }',
'                    },',
'                    progressView: $("#P17_NET") // Assuming progressView is P17_NET for simplicity',
'                });',
'',
'                update(model);',
'                model.fetchAll(function() {});',
'            }',
'        });',
'    });',
'',
'})(apex.jQuery);',
''))
,p_page_template_options=>'#DEFAULT#'
,p_page_comment=>wwv_flow_string.join(wwv_flow_t_varchar2(
'(function($) {',
'',
'    function update(model, addingRow) {',
'        var qtyKey = model.getFieldKey("QTY"),',
'            priceKey = model.getFieldKey("PRICE"),',
'            addValKey = model.getFieldKey("ADD_VAL"),',
'            subValKey = model.getFieldKey("SUB_VAL"),',
'            totalKey = model.getFieldKey("TOTAL"),',
'            total = 0,',
'            totalbefortax = 0,',
'            tax = 0;',
'',
'        model.forEach(function(record, index, id) {',
'            var qty = parseFloat(record[qtyKey]) || 0,',
'                price = parseFloat(record[priceKey]) || 0,',
'                addVal = parseFloat(record[addValKey]) || 0,',
'                subVal = parseFloat(record[subValKey]) || 0,',
'                meta = model.getRecordMetadata(id);',
'',
'            var product = qty * price;',
'            var addition = product + addVal;',
'            var subtraction = addition - subVal;',
'            var rowTotal = parseFloat(subtraction.toFixed(2));',
'',
'            record[totalKey] = rowTotal;',
'',
'            if (!meta.deleted && !meta.agg) {',
'                total += rowTotal;',
'                totalbefortax += product;',
'                tax += addVal;',
'            }',
'        });',
'',
'        // Refresh only if it''s not from adding a row',
'        if (!addingRow) {',
'            var ig = apex.region("INV").widget().interactiveGrid("getViews", "grid");',
'            ig.refresh();',
'        }',
'',
'        // Update summary items',
'        $s("P17_NET", parseFloat(total.toFixed(2)));',
'        $s("P17_INVTOTAL", parseFloat(totalbefortax.toFixed(2)));',
'        $s("P17_SUM_TAX", parseFloat(tax.toFixed(2)));',
'    }',
'',
'    $(function() {',
'        $("#INV").on("interactivegridviewmodelcreate", function(event, ui) {',
'            var model = ui.model;',
'',
'            if (ui.viewId === "grid") {',
'                model.subscribe({',
'                    onChange: function(type, change) {',
'                        if (type === "set" && ["QTY", "PRICE", "ADD_VAL", "SUB_VAL"].includes(change.field)) {',
'                            update(model, type === "add");',
'                        } else if (type !== "move" && type !== "metaChange") {',
'                            update(model, type === "add");',
'                        }',
'                    }',
'                });',
'',
'                update(model, false); // Initial load doesn''t result from adding a row',
'            }',
'        });',
'    });',
'',
'})(apex.jQuery);',
''))
,p_page_component_map=>'02'
);
