,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'var ig$ = apex.region("INV").widget(),',
'    view = ig$.interactiveGrid("getCurrentView"),',
'    model = view.model,',
'    selectedRecords = view.getSelectedRecords();',
'',
'// Check if records are selected.',
'if (!selectedRecords || selectedRecords.length === 0) {',
'    console.error(''No records are selected.'');',
'    return;',
'}',
'',
'// Ensure the model''s primary key is defined.',
'if (!model._pk || model._pk.length === 0) {',
'    console.error(''Model primary key is not defined or empty.'');',
'    return;',
'}',
'',
'var record = model.getRecord(selectedRecords[0][model._pk[0]]);',
'if (!record) {',
'    console.error(''Could not fetch the record.'');',
'    return;',
'}',
'',
'var itemIdValue = model.getValue(record, "ITEMID");',
'',
'var cols = view.getColumns(),',
'    col1 = cols.find(col => col.name === ''START_DATE''),',
'    col2 = cols.find(col => col.name === ''END_DATE'');',
'',
'if (!col1 || !col2) {',
'    console.error(''Could not find the required columns.'');',
'    return;',
'}',
'',
'// If ITEMID is 1, make the columns editable',
'if (itemIdValue === ''1'') {',
'    col1.editable = true;',
'    col2.editable = true;',
'} else { // Otherwise, disable them',
'    col1.editable = false;',
'    col2.editable = false;',
'}',
'',
'view.view$.grid("refreshColumns");',
''))
,p_server_condition_type=>'NEVER'
);
