,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'// Get a reference to the grid widget',
'var grid = apex.region("INV").widget().interactiveGrid("getViews", "grid");',
'',
'// Get all the data from the grid',
'var data = grid.model.records;',
'',
'// Initialize total variable',
'var total = 0;',
'',
'// Iterate over each row in the grid',
'data.forEach(function(row) {',
'    // Get the values from the columns for each row',
'    var qty = parseFloat(row.QTY) || 0;',
'    var price = parseFloat(row.PRICE) || 0;',
'    var addVal = parseFloat(row.ADD_VAL) || 0;',
'    var subVal = parseFloat(row.SUB_VAL) || 0;',
'',
'    // Calculate the total for the current row',
'    var rowTotal = qty * price + addVal - subVal;',
'',
'    // Add the row total to the overall total',
'    total += rowTotal;',
'});',
'',
'// Log or display the total',
'console.log("Total: " + total);',
''))
,p_server_condition_type=>'NEVER'
);
