,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_EXECUTE_PLSQL_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare ',
'MEMBER_end_mo varchar2(10);',
'MEMBER_ST_mo varchar2(10);',
'begin',
'--	',
'',
'    	if to_char(to_date(:P17_START_DATE,''yyyy/mm/dd''),''dd'')>15 then ',
'		--------------------',
'		if to_char(to_date(:P17_START_DATE,''yyyy/mm/dd''),''mm'')=12 ',
'        then MEMBER_ST_mo:=1;',
'		else',
'		MEMBER_ST_mo:=to_char(to_date(:P17_START_DATE,''yyyy/mm/dd''),''mm'')+1; ',
'		end if;',
'        	else',
'		MEMBER_ST_mo:=to_char(to_date(:P17_START_DATE,''yyyy/mm/dd''),''mm'');		',
'		end if;',
'',
'		--------------------',
'',
'	if to_char(to_date(:P17_END_DATE,''yyyy/mm/dd''),''dd'')<=15 then',
'		if  to_char(to_date(:P17_END_DATE,''yyyy/mm/dd''),''mm'')=1 then ',
'			MEMBER_end_mo:=12;',
'		else',
'		MEMBER_end_mo:=to_char(to_date(:P17_END_DATE,''yyyy/mm/dd''),''mm'')-1; ',
'		end if;',
'        else',
'        MEMBER_end_mo:=to_char(to_date(:P17_END_DATE,''yyyy/mm/dd''),''mm'');',
'	end if;',
'',
'    if to_char(to_date(:P17_START_DATE,''yyyy/mm/dd''),''yyyy'')=to_char(to_date(:P17_END_DATE,''yyyy/mm/dd''),''yyyy'')',
'    then ',
'    :P17_MONTHS:=to_number(MEMBER_end_mo)-to_number(MEMBER_ST_mo)+1;',
'    else',
'    if to_number(MEMBER_end_mo)<12 then ',
'     :P17_MONTHS:=to_number(MEMBER_end_mo)+12-to_number(MEMBER_ST_mo)+1;',
'     else ',
'	 :P17_MONTHS:=to_number(MEMBER_end_mo)-to_number(MEMBER_ST_mo)+1;',
'     end if;',
'     end if;',
'',
'		',
'       ',
'',
' end;',
''))
,p_attribute_02=>'P17_START_DATE,P17_END_DATE'
,p_attribute_03=>'P17_MONTHS'
,p_attribute_04=>'N'
,p_attribute_05=>'PLSQL'
,p_wait_for_result=>'Y'
);
