' select invid_start_with into v_invid_start_with from ISSUER where ISSUER_BRANCHID=:P17_BRANCHID;',
' exception when no_data_found then',
' null;',
' end;',
'begin',
'select v_invid_start_with||lpad(to_char(nvl(max(to_number(substr(invid,2))),0)+1 ),6,0) into :P17_INVID ',
'from main_inv where branchid=:P17_BRANCHID and return_flag=0;',
