wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(152166398586488974)
,p_process_sequence=>90
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'modify CUSTODY_DETAIL from shuttle'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'   l_input   VARCHAR2(10000) :=:P17_SHUTTLE_VALUE; -- Input string',
'   l_pos     PLS_INTEGER := 0;                          -- Position of the colon',
'   l_start   PLS_INTEGER := 1;                          -- Start of the current segment',
'   l_value   VARCHAR2(50);                              -- To hold each extracted value',
'   l_counter PLS_INTEGER := 1;                          -- Counter for tracking parts',
'BEGIN',
'   -- Loop through the string',
'   if :P17_SHUTTLE_VALUE is not null then',
'   LOOP',
'      -- Find the position of the next colon',
'      l_pos := INSTR(:P17_SHUTTLE_VALUE, '':'', l_start);',
'',
'      -- Extract the segment',
'      IF l_pos > 0 THEN',
'         l_value := SUBSTR(:P17_SHUTTLE_VALUE, l_start, l_pos - l_start);',
'      ELSE',
'         l_value := SUBSTR(:P17_SHUTTLE_VALUE, l_start); -- Last segment',
'      END IF;',
'',
'   update CUSTODY_DETAIL',
'      set inv_key=:P17_INV_KEY',
'      where id=substr(l_value,1,instr(l_value,''-'') -1 )',
'      and serial=substr(l_value,instr(l_value,''-'') +1 );',
'',
'      -- Increment the counter and update the start position',
'      l_counter := l_counter + 1;',
'      l_start := l_pos + 1;',
'',
'      -- Exit the loop when no more colons are found',
'      EXIT WHEN l_pos = 0;',
'   END LOOP;',
'   end if;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_type=>'NEVER'
,p_internal_uid=>16061438996749503
);
