 p_id=>wwv_flow_imp.id(287103365414155158)
,p_plug_name=>'CUSTODY_HEAD_CUST'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(272260547812647624)
,p_plug_display_sequence=>50
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
' SELECT DESCRIPTION,',
'        h.USER_NAME AS employee_id, ',
'        u.REAL_NAME AS employee_name, ',
'        h.TRANS_CODE, ',
'        h.TRANS_DATE, ',
'        d.AMOUNT AS expense_amount,  ',
'        D.NOTES,',
'        case when inv_key is not null then',
unistr('        ''\064A\0648\062C\062F \0641\0627\062A\0648\0631\0629'''),
'        else',
'        null',
'        end inv_status',
'    FROM ',
'        CUSTODY_HEAD h',
'    JOIN ',
'        ACC_USERS u ON h.USER_NAME = u.USER_NAME',
'    LEFT JOIN ',
'        CUSTODY_DETAIL d LEFT JOIN descriptions ON (DESCRIPTION_ID=descriptions.ID)',
'        ON (h.ID = d.ID) ',
'        WHERE custid=:P18_CUST  ',
'        AND TO_CHAR( h.TRANS_DATE, ''YYYY/MM/DD'') BETWEEN :P18_FROM_DATE AND :P18_TO_DATE',
'        ORDER BY H.ID',
'',
'       /* SELECT DESCRIPTION,id,short_DESCRIPTION',
'	           FROM descriptions ',
'order by id*/',
'',
'      ',
'     '))
,p_plug_source_type=>'NATIVE_IR'
,p_ajax_items_to_submit=>'P18_CUST,P18_FROM_DATE,P18_TO_DATE'
