,p_plug_template=>wwv_flow_imp.id(272260547812647624)
,p_plug_display_sequence=>20
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
' ',
'  SELECT ISSUER_BRANCHNAME,',
'inv_key,CUST_ID , CUST_NAME,',
' INVDATE ,MAIN_INV.INVID,sum(qty)--,price,',
' ,sum(decode( return_flag,0, nvl(PRICE,0)*nvl(DETAIL_INV.qty,0),nvl(PRICE,0)*nvl(DETAIL_INV.qty,0)*-1) )TOTAL',
' --sum(decode( return_flag,0, nvl(PRICE,0)*nvl(DETAIL_INV.qty,0), nvl(PRICE,0)*nvl(DETAIL_INV.qty,0))*-1) ) TOTAL,',
' ,sum(nvl(DETAIL_INV.add_val,0)) add_val,sum(nvl(DETAIL_INV.sub_val,0)) sub_val',
',sum(decode( return_flag,0,( nvl(PRICE,0)*nvl(DETAIL_INV.qty,0))+nvl(DETAIL_INV.add_val,0)-nvl(DETAIL_INV.sub_val,0),( nvl(PRICE,0)*nvl(DETAIL_INV.qty,0))+nvl(DETAIL_INV.add_val,0)-nvl(DETAIL_INV.sub_val,0)*-1) )NET',
',head_notes notes--,ITEMNAME,UNIT_NAME',
'FROM MAIN_INV join detail_inv',
'-- join items join units using(UNIT_ID) using (itemid) ',
'using(inv_key) ',
' JOIN CUST ON (MAIN_INV.CUST_ID=CUST.CUSTID AND',
'MAIN_INV.CUST_TYPE=CUST.CUST_TYPE     ) join ISSUER on (branchid=ISSUER_BRANCHID)',
'where  ',
'MAIN_INV.CUST_ID=:P20_CUST_ID -- AND MAIN_INV.CUST_TYPE=:P20_CUST_TYPE',
'group by ISSUER_BRANCHNAME,',
'inv_key,CUST_ID , CUST_NAME,',
' INVDATE ,INVID,head_notes',
'order by invdate desc,inv_key desc ',
'',
'--SELECT ISSUER_BRANCHNAME,ISSUER_BRANCHID FROM ISSUER ORDER BY ISSUER_BRANCHID',
'--to_char(invdate,''yyyymmdd'') between TO_CHAR(TO_DATE (:P21_FROM_DT_1 ,''dd/mm/YYYY'') ,''YYYYMMDD'')',
'--TO_CHAR(to_date(:P21_FROM_DT,''DD/MM/yyyy''),''yyyymmdd'') ',
'-- AND TO_CHAR(TO_DATE (:P21_TO_DT_1 ,''dd/mm/YYYY'') ,''YYYYMMDD'')',
'--to_char(to_date(:P21_FROM_DT,''mm/dd/yyyy''),''yyyymmdd'')',
' --and to_char(to_date(:P21_TO_DT,''mm/dd/yyyy''),''yyyymmdd'')',
'--WHERE MAIN_INV.CUST_ID=:P21_CUST_ID AND MAIN_INV.CUST_TYPE=:P21_CUST_TYPE',
'--GROUP BY inv_key,CUST_ID , CUST_NAME,',
' --INVDATE ,MAIN_INV.INVID,decode( return_flag,0,finaltotal,finaltotal*-1) ,head_notes',
'',
' --select UNIT_NAME,UNIT_ID from units',
' ',
' /*SELECT ',
'inv_key,CUST_ID , CUST_NAME,',
' INVDATE ,MAIN_INV.INVID,qty,price,',
' (decode( return_flag,0,( nvl(PRICE,0)*nvl(DETAIL_INV.qty,0)),( nvl(PRICE,0)*nvl(DETAIL_INV.qty,0))*-1) ) TOTAL,',
' (nvl(DETAIL_INV.add_val,0)) add_val,(nvl(DETAIL_INV.sub_val,0)) sub_val',
',(decode( return_flag,0,( nvl(PRICE,0)*nvl(DETAIL_INV.qty,0))+nvl(DETAIL_INV.add_val,0)-nvl(DETAIL_INV.sub_val,0),( nvl(PRICE,0)*nvl(DETAIL_INV.qty,0))+nvl(DETAIL_INV.add_val,0)-nvl(DETAIL_INV.sub_val,0)*-1) )NET',
',nvl(NOTES	,head_notes) notes,ITEMNAME,UNIT_NAME',
'FROM MAIN_INV join detail_inv join items join units using(UNIT_ID) using (itemid) using(inv_key)  JOIN CUST ON (MAIN_INV.CUST_ID=CUST.CUSTID AND',
'MAIN_INV.CUST_TYPE=CUST.CUST_TYPE     )',
'WHERE MAIN_INV.CUST_ID=:P20_CUST_ID AND MAIN_INV.CUST_TYPE=:P20_CUST_TYPE',
'--GROUP BY inv_key,CUST_ID , CUST_NAME,',
' --INVDATE ,MAIN_INV.INVID,decode( return_flag,0,finaltotal,finaltotal*-1) ,head_notes',
'',
' --select UNIT_NAME,UNIT_ID from units*/'))
,p_plug_source_type=>'NATIVE_IR'
,p_ajax_items_to_submit=>'P20_CUST_ID,P20_CUST_TYPE'
,p_prn_page_header=>'CUST_INVOICES'
