,p_process_name=>'pay'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'	v_alert number;',
'	V_payed_id NUMBER;',
'	V_PAYED_AMOUNT NUMBER;',
'	V_CUST_ID NUMBER;',
'	V_SDAD_TRANS_TYPE NUMBER;',
'	V_DEB_CRD NUMBER;',
'begin',
'DELETE MAIN_INV_PAYED WHERE PAYED_ID=:P25_TRANS_ID;',
'DELETE PAYED WHERE PAYED_ID=:P25_TRANS_ID;',
'',
'insert into payed   (PAYED_ID,  CUST_ID,  SAL_PURCH,  PAYED_DATE,  PAYED_AMOUNT,  NOTES,  SDAD_TRANS_TYPE, DEB_CRD,',
'   DEALER_ID,   PARENT_PAYED,  INV_CAT,  STORE_CODe)',
'   ',
'   select h.TRANS_id/*||lpad(serial,2,0)*/,id,2, TRANS_DATE,nvl(AMOUNT_BEFOR_TAX,0)+nvl(tax,0),',
'   notes_detail,TRANS_TYPE,0,id,null,inv_cat,STORE_CODe from',
'     CASH_TRANS_head h,cash_trans_detail d where h.trans_id=d.trans_id and h.trans_id=:P25_trans_id;--:CASH_TRANS_HEAD.trans_code||lpad(:TRANS_TYPE,3,0)||lpad(:CASH_TRANS_HEAD.CASH_ID,3,0);',
'     ',
'     SELECT payed_id,PAYED_AMOUNT ,CUST_ID,SDAD_TRANS_TYPE,DEB_CRD INTO V_payed_id,V_PAYED_AMOUNT,V_CUST_ID,V_SDAD_TRANS_TYPE,V_DEB_CRD',
'     FROM PAYED WHERE Payed_id=:P25_TRANS_id;',
'',
'     distibute_sdad(V_payed_id,V_PAYED_AMOUNT,V_CUST_ID,0,V_SDAD_TRANS_TYPE,0,V_DEB_CRD,:P25_INV_KEY);',
'  ',
' /* if :P25_INV_KEY is not null then ',
'     update main_inv set BOOK_INVNO=decode (BOOK_INVNO,null,:P25_TRANS_ID,BOOK_INVNO||'',''||:P25_TRANS_ID)',
'     where   INV_KEY=:P25_INV_KEY and rownum<2;',
'  end if;',
'*/',
'',
'    ',
'      ',
'     ',
'    ',
'     ',
' --  distibute_sdad(p_payed_id number,p_PAYED_AMOUNT number,p_CUST_ID number,P_INV_TYPE number,P_SDAD_TRANS_TYPE NUMBER,P_distibute_METHOD NUMBER,p_DB_CRD number)',
'',
'',
'end;',
'',
'',
''))
