wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(272376182035316165)
,p_plug_name=>'EMPLOYEE_TRANSACTION'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(272260547812647624)
,p_plug_display_sequence=>20
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
unistr('-- \0627\0633\062A\0639\0644\0627\0645 \0645\0648\062D\062F \0645\0639 \0631\0635\064A\062F \0623\0648\0644 \0627\0644\0645\062F\0629 \0648\0627\0644\062D\0631\0643\0627\062A \0648\062D\0633\0627\0628 \0627\0644\0631\0635\064A\062F \0627\0644\062A\0631\0627\0643\0645\064A'),
'SELECT ',
'    employee_id, ',
'    employee_name, ',
'    TRANS_CODE, ',
'    TRANS_DATE, ',
'    receipt_amount, ',
'    expense_amount, ',
'    NOTES,',
'    BALANCE,',
'    SEQ,',
'    cust_name,',
'    SERIAL,',
unistr('    -- \062D\0633\0627\0628 \0627\0644\0631\0635\064A\062F \0627\0644\062A\0631\0627\0643\0645\064A \0627\0644\0630\064A \064A\0634\0645\0644 \0631\0635\064A\062F \0623\0648\0644 \0627\0644\0645\062F\0629'),
'    SUM(NVL(receipt_amount, 0) - NVL(expense_amount, 0)) ',
'    OVER (PARTITION BY employee_id ORDER BY TRANS_DATE, SEQ, TRANS_CODE,SERIAL) AS cumulative_balance',
'FROM (',
unistr('    -- \0627\0633\062A\0639\0644\0627\0645 \0631\0635\064A\062F \0623\0648\0644 \0627\0644\0645\062F\0629'),
'    SELECT ',
'        employee_id,',
'        employee_name,',
'        0 AS TRANS_CODE,',
'        TO_CHAR(NVL(TO_DATE(:P27_FROM_DATE, ''YYYY-MM-DD'') - 1, SYSDATE - 8), ''YYYY/MM/DD'') AS TRANS_DATE,',
'        CASE WHEN SUM(NVL(receipt_amount, 0) - NVL(expense_amount, 0)) > 0 THEN ',
'            SUM(NVL(receipt_amount, 0) - NVL(expense_amount, 0)) END AS receipt_amount,',
'        CASE WHEN SUM(NVL(receipt_amount, 0) - NVL(expense_amount, 0)) < 0 THEN ',
'            abs(SUM(NVL(receipt_amount, 0) - NVL(expense_amount, 0)) ) END AS expense_amount,',
unistr('        ''\0631\0635\064A\062F \0623\0648\0644 \0627\0644\0645\062F\0629'' AS NOTES,'),
'        emp_balance(employee_id) AS BALANCE,',
'        -1 AS SEQ,',
'        NULL AS cust_name,',
'        0 AS SERIAL',
'    FROM (',
unistr('        -- \0627\0644\062D\0631\0643\0627\062A \0627\0644\0645\062F\064A\0646\0629 \0642\0628\0644 \0627\0644\062A\0627\0631\064A\062E \0627\0644\0645\062D\062F\062F'),
'        SELECT ',
'            TO_CHAR(d.ID) AS employee_id, ',
'            u.REAL_NAME AS employee_name, ',
'            d.AMOUNT AS receipt_amount, ',
'            NULL AS expense_amount',
'        FROM ',
'            CASH_TRANS_HEAD h',
'        JOIN ',
'            CASH_TRANS_DETAIL d ON h.TRANS_ID = d.TRANS_ID',
'        JOIN ',
'            ACC_USERS u ON d.ID = u.USER_NAME',
'        WHERE ',
'            d.AMOUNT > 0',
'            AND (:P27_USER_NAME = 0 OR TO_CHAR(d.ID) = :P27_USER_NAME)',
'            AND TO_CHAR(TRANS_DATE, ''YYYY/MM/DD'') < NVL(:P27_FROM_DATE, SYSDATE-7)',
'            and flag=1',
'        UNION ALL',
'',
unistr('        -- \0627\0644\062D\0631\0643\0627\062A \0627\0644\062F\0627\0626\0646\0629 \0642\0628\0644 \0627\0644\062A\0627\0631\064A\062E \0627\0644\0645\062D\062F\062F'),
'        SELECT ',
'            h.USER_NAME AS employee_id, ',
'            u.REAL_NAME AS employee_name, ',
'            NULL AS receipt_amount, ',
'            d.AMOUNT AS expense_amount',
'        FROM ',
'            CUSTODY_HEAD h',
'        JOIN ',
'            ACC_USERS u ON h.USER_NAME = u.USER_NAME',
'        LEFT JOIN ',
'            CUSTODY_DETAIL d ON h.ID = d.ID',
'        WHERE ',
'            (:P27_USER_NAME = 0 OR TO_CHAR(h.USER_NAME) = :P27_USER_NAME)',
'            AND TO_CHAR(TRANS_DATE, ''YYYY/MM/DD'') < NVL(:P27_FROM_DATE, SYSDATE-7)',
'    )',
'    GROUP BY employee_id, employee_name',
'',
'    UNION ALL',
'',
unistr('    -- \0627\0633\062A\0639\0644\0627\0645 \0627\0644\062D\0631\0643\0627\062A'),
'    SELECT ',
'        employee_id, ',
'        employee_name, ',
'        TRANS_CODE, ',
'        TO_CHAR(TRANS_DATE, ''YYYY/MM/DD'') AS TRANS_DATE, ',
'        receipt_amount, ',
'        expense_amount, ',
'        NOTES,',
'        emp_balance(employee_id) AS BALANCE,',
'        SEQ,',
'        cust_name,',
'         SERIAL',
'    FROM (',
unistr('        -- \0627\0644\062D\0631\0643\0627\062A \0627\0644\0645\062F\064A\0646\0629 (\0627\0633\062A\0644\0627\0645 \0627\0644\0639\0647\062F\0629)'),
'        SELECT ',
'            TO_CHAR(d.ID) AS employee_id, ',
'            u.REAL_NAME AS employee_name, ',
'            h.TRANS_CODE, ',
'            h.TRANS_DATE, ',
'            d.AMOUNT AS receipt_amount, ',
'            NULL AS expense_amount, ',
unistr('            nvl(H.NOTES,''\0635\0631\0641 \0645\0646 \062E\0632\064A\0646\0629'')   NOTES,'),
'            0 AS SEQ, ',
'            NULL AS cust_name, ',
'            SERIAL',
'        FROM ',
'            CASH_TRANS_HEAD h',
'        JOIN ',
'            CASH_TRANS_DETAIL d ON h.TRANS_ID = d.TRANS_ID',
'        JOIN ',
'            ACC_USERS u ON d.ID = u.USER_NAME',
'        WHERE ',
'            d.AMOUNT > 0',
'            AND (:P27_USER_NAME = 0 OR TO_CHAR(d.ID) = :P27_USER_NAME)',
'            and flag=1',
'        UNION ALL',
'',
unistr('        -- \0627\0644\062D\0631\0643\0627\062A \0627\0644\062F\0627\0626\0646\0629 (\0635\0631\0641 \0627\0644\0639\0647\062F\0629)'),
'        SELECT ',
'            h.USER_NAME AS employee_id, ',
'            u.REAL_NAME AS employee_name, ',
'            h.TRANS_CODE, ',
'            h.TRANS_DATE, ',
'            NULL AS receipt_amount, ',
'            d.AMOUNT AS expense_amount, ',
'            DESCRIPTION || NVL2(D.NOTES, ''-'', '''') || D.NOTES AS NOTES, ',
'            1 AS SEQ, ',
'            cust.cust_name, ',
'            d.SERIAL',
'        FROM ',
'            CUSTODY_HEAD h',
'        JOIN ',
'            ACC_USERS u ON h.USER_NAME = u.USER_NAME',
'        LEFT JOIN ',
'            CUSTODY_DETAIL d LEFT JOIN descriptions ON (DESCRIPTION_ID = descriptions.ID) ON h.ID = d.ID',
'            LEFT JOIN cust ON d.CUSTID = cust.CUSTID',
'        WHERE ',
'            (:P27_USER_NAME = 0 OR TO_CHAR(h.USER_NAME) = :P27_USER_NAME)',
'    )',
'    WHERE TO_CHAR(TRANS_DATE, ''YYYY/MM/DD'') BETWEEN NVL(:P27_FROM_DATE, SYSDATE-7) AND NVL(:P27_TO_DATE, SYSDATE))',
'ORDER BY ',
'    employee_id, ',
'    TRANS_DATE, ',
'    SEQ, ',
'    TRANS_CODE,SERIAL;',
''))
,p_plug_source_type=>'NATIVE_IR'
,p_ajax_items_to_submit=>'P27_USER_NAME,P27_FROM_DATE,P27_TO_DATE'
,p_prn_page_header=>'EMPLOYEE_TRANSACTION'
);
