prompt --application/pages/page_00030
begin
wwv_flow_imp_page.create_page(
 p_id=>30
,p_name=>'tasks_rep'
,p_alias=>'TASKS-REP'
,p_step_title=>'tasks_rep'
,p_warn_on_unsaved_changes=>'N'
,p_autocomplete_on_off=>'OFF'
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'13'
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(154105642141048191)
,p_plug_name=>'tasks_rep'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(272260547812647624)
,p_plug_display_sequence=>20
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
' SELECT TASK_ID,',
'       TASK_NAME,',
'       TASK_DESC,',
'       START_PLAN_DATE,',
'       END_PLAN_DATE,',
'       START_ACTUAL_DATE,',
'       END_ACTUAL_DATE,',
'       CANCEL_CHK,',
'       REMIND_BEFOR_START,',
'       REMIND_EVERY,',
'       CUST_ID,',
'       C.CUST_NAME,real_name, CASE ',
unistr('        WHEN END_ACTUAL_DATE IS NOT NULL THEN ''\0645\0646\062A\0647\064A\0629'''),
unistr('        WHEN START_ACTUAL_DATE IS NOT NULL THEN ''\0645\0631\062D\0644\0629 \0627\0644\062A\0646\0641\064A\0630'''),
unistr('        WHEN END_ACTUAL_DATE IS NULL AND END_PLAN_DATE <SYSDATE THEN ''\0645\062A\0623\062E\0631\0629'''),
unistr('        ELSE ''\0645\0641\0646\0648\062D\0629'' END  task_status ,TAX_OFFICE_NAME'),
'  FROM CUST_TASKS CT, CUST C ,acc_users',
' WHERE CT.CUST_ID = c.CUSTID --and(:APP_ROLE_ID IN (1,2) or upper(ct.user_name)=:app_user)',
'and ct.user_name=acc_users.user_name',
'',
' AND (:P30_STATUS =9 ',
' OR (:P30_STATUS =4 AND END_ACTUAL_DATE IS NOT NULL) ',
' OR (:P30_STATUS =1 AND END_ACTUAL_DATE IS  NULL)',
' --OR (:P30_STATUS =1 AND START_ACTUAL_DATE IS NULL AND START_PLAN_DATE <SYSDATE) ',
