' )',
' AND ( (TO_CHAR(START_PLAN_DATE,''MMYYYY'')=TO_CHAR(SYSDATE,''MMYYYY''))',
' OR  (START_PLAN_DATE<=SYSDATE AND END_ACTUAL_DATE IS NULL)',
'  OR (START_ACTUAL_DATE IS NOT NULL AND END_ACTUAL_DATE IS NULL) ',
'  ) ',
' AND  (:P30_USER_NAME = ''0'' OR TO_CHAR(CT.USER_NAME) = :P30_USER_NAME)',
'',
'  order by START_PLAN_DATE DESC'))
,p_plug_source_type=>'NATIVE_IR'
