 p_id=>35
,p_name=>'file_tansfer'
,p_alias=>'FILE-TANSFER1'
,p_step_title=>'file_tansfer'
,p_autocomplete_on_off=>'OFF'
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'18'
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(164599870909032774)
,p_plug_name=>'file_tansfer'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(272260547812647624)
,p_plug_display_sequence=>160
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    f.ID,',
'    f.TRANS_DATE,',
'    f.FROM_TYPE,',
'    f.TO_TYPE,',
'',
'    CASE ',
'        WHEN f.FROM_TYPE = 1 THEN c1.CUST_NAME',
'        WHEN f.FROM_TYPE = 0 THEN f.GOVERNMENT_AGENCY',
'        WHEN f.FROM_TYPE = 2 THEN TO_CHAR(f.EMPLOYEE)',
'    END AS FROM_NAME,',
'',
'    CASE ',
'        WHEN f.TO_TYPE = 1 THEN c2.CUST_NAME',
'        WHEN f.TO_TYPE = 0 THEN f.TO_GOVERNMENT_AGENCY',
'        WHEN f.TO_TYPE = 2 THEN TO_CHAR(f.TO_EMOLOYYEE)',
'    END AS TO_NAME,',
'',
'    f.DELIVERER,',
'    f.THE_RECIPIENT,',
'',
'    cf.FILE_DESC,',
'    cf.FILE_ID AS LINK2,',
'    cf.FILE_name,',
'    cf.CUSTOMER_ID,',
'    cf.CUSTOMER_ID AS LINK',
'',
'',
'FROM FILE_TRANSFER f',
'LEFT JOIN CUST c1 ',
'    ON f.CUSTOMER = c1.CUSTID',
'LEFT JOIN CUST c2 ',
'    ON f.TO_CUSTOMER = c2.CUSTID',
'LEFT JOIN CUSTOMER_FILE cf',
'    ON f.FILE_ID = cf.FILE_ID',
'WHERE f.FILE_ID=:P35_FILE_ID'))
,p_plug_source_type=>'NATIVE_IR'
,p_ajax_items_to_submit=>'P35_FILE_ID'
,p_prn_page_header=>'file_tansfer'
,p_ai_enabled=>false
);
